import { useState, useRef } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { useData } from "../contexts/DataContext";
import { X } from "lucide-react";
import { toast } from "sonner";

export default function UpInvoice() {
  const { id } = useParams();
  const { orders = [], setInvoiceUploaded } = useData();
  const navigate = useNavigate();

  const fileInputRef = useRef(null);
  const order = orders.find((o) => String(o.id) === String(id));

  const [file, setFile] = useState(null);
  const [dragOver, setDragOver] = useState(false);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  if (!order) {
    return (
      <div style={{ fontFamily: "'Plus Jakarta Sans', sans-serif", padding: 40 }}>
        <p style={{ color: "#6B7280" }}>Pesanan tidak ditemukan.</p>
        <button
          onClick={() => navigate("/status-pengiriman")}
          style={{
            marginTop: 16, background: "#F59E0B", color: "#fff", border: "none",
            borderRadius: 8, padding: "10px 24px", fontSize: 14, fontWeight: 700, cursor: "pointer",
          }}
        >
          Kembali
        </button>
      </div>
    );
  }

  const handleFile = (f) => {
    if (!f) return;
    const validType = f.type === "application/pdf" || f.type === "image/png";
    if (!validType) { toast.error("File harus PDF atau PNG"); return; }
    setFile(f);
  };

  const handleSubmit = async () => {
    if (!file) { toast.error("Pilih file terlebih dahulu"); return; }
    try {
      setLoading(true);
      await new Promise((res) => setTimeout(res, 800));
      setInvoiceUploaded(order.id);
      setSuccess(true);
    } catch {
      toast.error("Gagal upload invoice");
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700;800&display=swap');
        @keyframes popIn {
          from { opacity: 0; transform: scale(0.88); }
          to   { opacity: 1; transform: scale(1); }
        }
      `}</style>

      {/* ── SUCCESS MODAL OVERLAY ── */}
      {success && (
        <div style={{
          position: "fixed",
          inset: 0,
          background: "rgba(0,0,0,0.4)",
          backdropFilter: "blur(3px)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          zIndex: 999,
          padding: 24,
        }}>
          <div style={{
            background: "#fff",
            borderRadius: 20,
            border: "2px solid #60A5FA",
            boxShadow: "0 8px 40px rgba(0,0,0,0.16)",
            padding: "56px 48px",
            textAlign: "center",
            maxWidth: 420,
            width: "100%",
            animation: "popIn 0.25s ease",
          }}>
            <div style={{
              width: 96, height: 96, borderRadius: "50%",
              background: "#DCFCE7", border: "2px solid #22C55E",
              display: "flex", alignItems: "center", justifyContent: "center",
              margin: "0 auto 28px",
            }}>
              <svg width="44" height="44" viewBox="0 0 44 44" fill="none">
                <path d="M10 22L18 30L34 14" stroke="#22C55E" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
            </div>

            <h2 style={{ fontSize: 20, fontWeight: 700, color: "#111827", margin: "0 0 12px" }}>
              Invoice Berhasil Terkirim
            </h2>
            <p style={{ fontSize: 13, color: "#6B7280", margin: "0 0 32px", lineHeight: 1.6 }}>
              Shelter akan menghubungi anda atau anda bisa menghubungi shelter
            </p>

            <button
              onClick={() => navigate("/status-pengiriman")}
              style={{
                background: "#F59E0B", color: "#fff", border: "none",
                borderRadius: 10, padding: "11px 36px", fontSize: 14,
                fontWeight: 700, cursor: "pointer", fontFamily: "inherit",
              }}
            >
              Kembali ke Status Pesanan
            </button>
          </div>
        </div>
      )}

      {/* ── HALAMAN UTAMA ── */}
      <div style={{ fontFamily: "'Plus Jakarta Sans', sans-serif", background: "#F8F9FB", minHeight: "100vh", padding: "40px 40px" }}>
        {/* ... sisa JSX halaman upload tetap sama ... */}
      </div>
    </>
  );
}
